import { GoogleGenAI, Type, Modality } from "@google/genai";
import { HoroscopeReading } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

export const generateHoroscopeText = async (
  name: string,
  birthDate: string,
  birthPlace: string,
  focus: string
): Promise<HoroscopeReading> => {
  const prompt = `
    Generate a comprehensive horoscope reading for ${name}, born on ${birthDate} in ${birthPlace}.
    Focus area: ${focus}.
    Include insights from:
    1. Western Astrology (Sun, Moon, Rising if inferable, current transits)
    2. Chinese Zodiac
    3. Tarot (Simulate a 3-card spread)
    4. Native American Totem
    5. Buddhist cosmic philosophy

    Format as JSON.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                content: { type: Type.STRING },
                icon: { type: Type.STRING }
              }
            }
          },
          luckyNumbers: { type: Type.ARRAY, items: { type: Type.NUMBER } },
          luckyColors: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      }
    }
  });

  if (!response.text) throw new Error("No text generated");
  return JSON.parse(response.text) as HoroscopeReading;
};

export const generateHoroscopeImage = async (description: string): Promise<string> => {
  const prompt = `A mystical, ethereal, high-quality digital art masterpiece representing: ${description}. Cosmic style, intricate details, glowing nebulas, ancient symbols.`;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-image",
    contents: {
      parts: [{ text: prompt }]
    }
  });

  // Extract image
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData && part.inlineData.data) {
      return part.inlineData.data;
    }
  }
  throw new Error("No image generated");
};

export const editHoroscopeImage = async (base64Image: string, instruction: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-image",
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: "image/png",
            data: base64Image
          }
        },
        { text: instruction }
      ]
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData && part.inlineData.data) {
      return part.inlineData.data;
    }
  }
  throw new Error("No edited image generated");
};

export const generateTTS = async (text: string): Promise<Uint8Array> => {
  // Prepend style instructions to the text to guide the model's prosody
  const styledText = `Speak in a deep, soothing, and mystical tone, with a slow and deliberate pace, like an ancient storyteller: ${text}`;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: {
      parts: [{ text: styledText }]
    },
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          // Kore offers a balanced, soothing feminine voice suitable for mystical content
          prebuiltVoiceConfig: { voiceName: "Kore" }
        }
      }
    }
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio generated");

  const binaryString = atob(base64Audio);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

