      }
    };
  }, []);

  const formatTextForSpeech = (data: HoroscopeReading) => {
    // Add pauses and softer transitions for the "natural voice modulation"
    let text = `Welcome, seeker. Here is your unified cosmic reading. ... \n\n ${data.summary} ... \n\n`;

    const transitions = [
      "Let us now look to the stars.",
      "In the realm of",
      "Regarding the cards,",
      "The ancient spirits speak of",
      "And finally, wisdom from"
    ];

    data.sections.forEach((section, index) => {
      const transition = transitions[index % transitions.length];
      // Use the section title but soften it in the sentence structure
      text += `${transition} ... ${section.title}. ... ${section.content} ... \n\n`;
    });

    text += "May these insights light your way.";
    return text;
