          to { opacity: 1; transform: translateY(0); }
        }
        .animate-fade-in-up {
          animation: fadeInUp 0.8s ease-out forwards;
        }
        .animate-pulse-slow {
          animation: pulse 3s cubic-bezier(0.4, 0, 0.6, 1) infinite;
        }
      `}</style>
    </div>
  );
};

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { HoroscopeReading } from '../types';
import { pcmToWav } from '../services/audioUtils';
import ImageEditor from './ImageEditor';
import { formatTextForSpeech } from '../services/geminiService';

interface Props {
  data: HoroscopeReading;
  imageData: string; // base64
  preloadedAudio: Uint8Array | null;
  timestamp?: number;
  onLiveClick: () => void;
  onReset: () => void;
  onSave?: () => void; // Optional onSave callback
}

const HoroscopeView: React.FC<Props> = ({ data, imageData: initialImage, preloadedAudio, timestamp, onLiveClick, onReset, onSave }) => {
  const [currentImage, setCurrentImage] = useState(initialImage);
  const [isPlaying, setIsPlaying] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const audioRef = useRef<HTMLAudioElement | null>(null);

  // Initialize Audio
  useEffect(() => {
    if (!preloadedAudio) return;

    try {
      // Create WAV blob from preloaded PCM data
      const wavBlob = pcmToWav(preloadedAudio, 24000); 
      const audioUrl = URL.createObjectURL(wavBlob);

      const audio = new Audio(audioUrl);
      // Natural speed for Zephyr voice
      audio.playbackRate = 1.0; 

      audio.onended = () => setIsPlaying(false);
      audio.onpause = () => setIsPlaying(false);
      audio.onplay = () => setIsPlaying(true);

      audioRef.current = audio;
    } catch (e) {
      console.error("Audio Setup Error", e);
    }

    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
    };
  }, [preloadedAudio]);

  const handlePlayPause = async () => {
    if (audioRef.current) {
      if (audioRef.current.paused) {
        await audioRef.current.play();
      } else {
        audioRef.current.pause();
      }
    }
  };

  const handleStop = () => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current.currentTime = 0;
      setIsPlaying(false);
    }
  };

  const handleRewind = () => {
    if (audioRef.current) {
      audioRef.current.currentTime = Math.max(0, audioRef.current.currentTime - 15);
    }
  };

  // --- Download Handlers ---

  const downloadAudio = () => {
    if (!preloadedAudio) return;
    const wavBlob = pcmToWav(preloadedAudio, 24000);
    const url = URL.createObjectURL(wavBlob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'omni-cosmos-reading.wav';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const downloadImage = () => {
    const a = document.createElement('a');
    a.href = `data:image/png;base64,${currentImage}`;
    a.download = 'omni-cosmos-art.png';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  const downloadText = () => {
    const textContent = formatTextForSpeech(data); // Reuse the formatted text logic
    const blob = new Blob([textContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'omni-cosmos-reading.txt';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleShare = async () => {
    const shareData = {
      title: 'Omni-Cosmos Reading',
      text: `My Cosmic Reading:\n\n${data.summary}\n\nLucky Numbers: ${data.luckyNumbers.join(', ')}`,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        console.log('Error sharing', err);
      }
