  init() {
    if (!this.ctx) {
       const AudioContext = window.AudioContext || (window as any).webkitAudioContext;
       this.ctx = new AudioContext();
       this.masterGain = this.ctx.createGain();
       this.masterGain.gain.value = 0.15; // Keep background subtle
       this.masterGain.connect(this.ctx.destination);
    }
    if (this.ctx.state === 'suspended') {
        this.ctx.resume().catch(e => console.error("Audio resume failed", e));
    }
  }

  play(type: AmbientType) {
    this.stop(); // Stop current sounds

    if (type === 'void') return;

    this.init(); // Ensure context exists
    if (!this.ctx || !this.masterGain) return;

    if (type === 'winds') this.startWinds();
    if (type === 'chimes') this.startChimes();
  }

  stop() {
    // Stop and disconnect all continuous nodes
    this.activeNodes.forEach(n => {
        try {
            n.disconnect();
            if ((n as any).stop) (n as any).stop();
        } catch(e) {}
    });
    this.activeNodes = [];

    // Clear interval for rhythmic sounds
    if (this.chimeInterval) {
        clearInterval(this.chimeInterval);
        this.chimeInterval = null;
    }
  }

  private startWinds() {
     if (!this.ctx || !this.masterGain) return;

     // Brown/Pinkish Noise generation
     const bufferSize = 2 * this.ctx.sampleRate;
     const buffer = this.ctx.createBuffer(1, bufferSize, this.ctx.sampleRate);
     const output = buffer.getChannelData(0);
     let lastOut = 0;
     for (let i = 0; i < bufferSize; i++) {
         const white = Math.random() * 2 - 1;
         output[i] = (lastOut + (0.02 * white)) / 1.02;
         lastOut = output[i];
         output[i] *= 3.5; // Compensate for gain loss
     }

     const noise = this.ctx.createBufferSource();
     noise.buffer = buffer;
     noise.loop = true;

     // Lowpass Filter to create "wind" effect from noise
     const filter = this.ctx.createBiquadFilter();
     filter.type = 'lowpass';
     filter.frequency.value = 400; 

     // LFO to modulate the filter frequency (simulate gusting wind)
     const lfo = this.ctx.createOscillator();
     lfo.type = 'sine';
     lfo.frequency.value = 0.1; // Slow gusts
     const lfoGain = this.ctx.createGain();
     lfoGain.gain.value = 300; // Modulation depth

     lfo.connect(lfoGain);
     lfoGain.connect(filter.frequency);

     noise.connect(filter);
     filter.connect(this.masterGain);

     noise.start();
     lfo.start();

     this.activeNodes.push(noise, filter, lfo, lfoGain);
  }

  private startChimes() {
     if (!this.ctx || !this.masterGain) return;

     const scheduleChime = () => {
         if (!this.ctx || !this.masterGain) return;
         const osc = this.ctx.createOscillator();
         const gain = this.ctx.createGain();

         // Pentatonic scale frequencies
         const freqs = [261.63, 293.66, 329.63, 392.00, 440.00, 523.25]; 
         // Randomly pick frequency and occasionally shift octave
         const freq = freqs[Math.floor(Math.random() * freqs.length)] * (Math.random() > 0.7 ? 2 : 1);

         osc.frequency.value = freq;
         osc.type = 'sine'; // Sine waves sound like pure bells/chimes

         // Envelope
         const now = this.ctx.currentTime;
         gain.gain.setValueAtTime(0, now);
         gain.gain.linearRampToValueAtTime(0.2, now + 0.1); // Fast attack
         gain.gain.exponentialRampToValueAtTime(0.001, now + 5); // Long decay

         osc.connect(gain);
         gain.connect(this.masterGain!);

         osc.start();
         osc.stop(now + 5);
         // Transient nodes don't need to be tracked in activeNodes for stop() as they expire,
         // but the interval clearing handles stopping the creation of new ones.
     };

     scheduleChime(); // Play one immediately
     // Randomize interval slightly in a real app, but fixed is fine here
     this.chimeInterval = setInterval(scheduleChime, 4000);
  }

  cleanup() {
      this.stop();
      if (this.ctx) {
          this.ctx.close().catch(e => console.error("Audio close failed", e));
          this.ctx = null;
      }
  }
}

import React, { useState, useEffect, useRef } from 'react';
import { HoroscopeReading } from '../types';
import { pcmToWav } from '../services/audioUtils';
import ImageEditor from './ImageEditor';
import { formatTextForSpeech } from '../services/geminiService';
import { AmbientService, AmbientType } from '../services/ambientService';

interface Props {
  data: HoroscopeReading;
  imageData: string; // base64
  preloadedAudio: Uint8Array | null;
  timestamp?: number;
  onLiveClick: () => void;
  onReset: () => void;
  onSave?: () => void; // Optional onSave callback
}

const HoroscopeView: React.FC<Props> = ({ data, imageData: initialImage, preloadedAudio, timestamp, onLiveClick, onReset, onSave }) => {
  const [currentImage, setCurrentImage] = useState(initialImage);
  const [isPlaying, setIsPlaying] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [ambientMode, setAmbientMode] = useState<AmbientType>('winds'); // Default to Cosmic Winds

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const ambientServiceRef = useRef<AmbientService | null>(null);

  // Initialize Audio (Voice)
  useEffect(() => {
    if (!preloadedAudio) return;

    try {
      // Create WAV blob from preloaded PCM data
      const wavBlob = pcmToWav(preloadedAudio, 24000); 
      const audioUrl = URL.createObjectURL(wavBlob);

      const audio = new Audio(audioUrl);
      // Natural speed for Zephyr voice
      audio.playbackRate = 1.0; 

      audio.onended = () => setIsPlaying(false);
      audio.onpause = () => setIsPlaying(false);
      audio.onplay = () => setIsPlaying(true);

      audioRef.current = audio;

      // Auto-play voice on mount
      const playPromise = audio.play();
      if (playPromise !== undefined) {
        playPromise.catch(error => {
          console.log("Auto-play prevented (Voice):", error);
        });
      }

    } catch (e) {
      console.error("Audio Setup Error", e);
    }

    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
    };
  }, [preloadedAudio]);

  // Initialize Ambient Service
  useEffect(() => {
    ambientServiceRef.current = new AmbientService();
    // Auto-play ambient
    ambientServiceRef.current.play(ambientMode);

    return () => {
      if (ambientServiceRef.current) {
        ambientServiceRef.current.cleanup();
      }
    };
  }, []); // Only run on mount to init

  // Handle Ambient Mode Switching
  useEffect(() => {
    if (ambientServiceRef.current) {
      ambientServiceRef.current.play(ambientMode);
    }
  }, [ambientMode]);

  const handlePlayPause = async () => {
    if (audioRef.current) {
      if (audioRef.current.paused) {
        await audioRef.current.play();
      } else {
        audioRef.current.pause();
      }
    }
  };

  const handleStop = () => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current.currentTime = 0;
      setIsPlaying(false);
    }
  };

  const handleRewind = () => {
    if (audioRef.current) {
      audioRef.current.currentTime = Math.max(0, audioRef.current.currentTime - 15);
    }
  };

  // --- Download Handlers ---

  const downloadAudio = () => {
    if (!preloadedAudio) return;
    const wavBlob = pcmToWav(preloadedAudio, 24000);
    const url = URL.createObjectURL(wavBlob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'omni-cosmos-reading.wav';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const downloadImage = () => {
    const a = document.createElement('a');
    a.href = `data:image/png;base64,${currentImage}`;
    a.download = 'omni-cosmos-art.png';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
  };

  const downloadText = () => {
    const textContent = formatTextForSpeech(data); // Reuse the formatted text logic
    const blob = new Blob([textContent], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'omni-cosmos-reading.txt';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleShare = async () => {
    const shareData = {
      title: 'Omni-Cosmos Reading',
      text: `My Cosmic Reading:\n\n${data.summary}\n\nLucky Numbers: ${data.luckyNumbers.join(', ')}`,
    };

    if (navigator.share) {
      try {
        await navigator.share(shareData);
      } catch (err) {
        console.log('Error sharing', err);
      }
    } else {
      navigator.clipboard.writeText(shareData.text);
      alert("Reading summary copied to clipboard!");
    }
  };

