import React, { useState, useEffect, useRef } from 'react';
import { HoroscopeReading } from '../types';
import { pcmToWav } from '../services/audioUtils';
import ImageEditor from './ImageEditor';
import { formatTextForSpeech } from '../services/geminiService';
import { AmbientService, AmbientType } from '../services/ambientService';

// --- Scroll Animation Component ---
const FadeInSection: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  const [isVisible, setVisible] = useState(false);
  const domRef = useRef<HTMLDivElement>(null);

  useEffect(() => {
    const observer = new IntersectionObserver(entries => {
      entries.forEach(entry => {
        if (entry.isIntersecting) {
          setVisible(true);
        }
      });
    }, { threshold: 0.15 }); // Trigger when 15% visible

    const ref = domRef.current;
    if (ref) observer.observe(ref);

    return () => {
      if (ref) observer.unobserve(ref);
    };
  }, []);

  return (
    <div
      ref={domRef}
      className={`transition-all duration-1000 ease-out transform ${
        isVisible ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-12'
      }`}
    >
      {children}
    </div>
  );
};

interface Props {
  data: HoroscopeReading;
  imageData: string; // base64
  preloadedAudio: Uint8Array | null;
  timestamp?: number;
  onLiveClick: () => void;
  onReset: () => void;
  onSave?: () => void; // Optional onSave callback
}

const HoroscopeView: React.FC<Props> = ({ data, imageData: initialImage, preloadedAudio, timestamp, onLiveClick, onReset, onSave }) => {
  const [currentImage, setCurrentImage] = useState(initialImage);
  const [isPlaying, setIsPlaying] = useState(false);
  const [showEditor, setShowEditor] = useState(false);
  const [isSaved, setIsSaved] = useState(false);
  const [ambientMode, setAmbientMode] = useState<AmbientType>('winds'); // Default to Cosmic Winds

  const audioRef = useRef<HTMLAudioElement | null>(null);
  const ambientServiceRef = useRef<AmbientService | null>(null);

  // Initialize Audio (Voice)
  useEffect(() => {
    if (!preloadedAudio) return;

    try {
      // Create WAV blob from preloaded PCM data
      const wavBlob = pcmToWav(preloadedAudio, 24000); 
      const audioUrl = URL.createObjectURL(wavBlob);

      const audio = new Audio(audioUrl);
      // Natural speed for Zephyr voice
      audio.playbackRate = 1.0; 

      audio.onended = () => setIsPlaying(false);
      audio.onpause = () => setIsPlaying(false);
      audio.onplay = () => setIsPlaying(true);

      audioRef.current = audio;

      // Auto-play voice on mount
      const playPromise = audio.play();
      if (playPromise !== undefined) {
        playPromise.catch(error => {
          console.log("Auto-play prevented (Voice):", error);
        });
      }

    } catch (e) {
      console.error("Audio Setup Error", e);
    }

    return () => {
      if (audioRef.current) {
        audioRef.current.pause();
        audioRef.current = null;
      }
    };
  }, [preloadedAudio]);

  // Initialize Ambient Service
  useEffect(() => {
    ambientServiceRef.current = new AmbientService();
    // Auto-play ambient
    ambientServiceRef.current.play(ambientMode);

    return () => {
      if (ambientServiceRef.current) {
        ambientServiceRef.current.cleanup();
      }
    };
  }, []); // Only run on mount to init

  // Handle Ambient Mode Switching
  useEffect(() => {
    if (ambientServiceRef.current) {
      ambientServiceRef.current.play(ambientMode);
    }
  }, [ambientMode]);

  const handlePlayPause = async () => {
    if (audioRef.current) {
      if (audioRef.current.paused) {
        await audioRef.current.play();
      } else {
        audioRef.current.pause();
      }
    }
  };

  const handleStop = () => {
    if (audioRef.current) {
      audioRef.current.pause();
      audioRef.current.currentTime = 0;
      setIsPlaying(false);
    }
  };

  const handleRewind = () => {
    if (audioRef.current) {
      audioRef.current.currentTime = Math.max(0, audioRef.current.currentTime - 15);
    }
  };

  // --- Download Handlers ---

  const downloadAudio = () => {
    if (!preloadedAudio) return;
    const wavBlob = pcmToWav(preloadedAudio, 24000);
    const url = URL.createObjectURL(wavBlob);
    const a = document.createElement('a');
    a.href = url;
    a.download = 'omni-cosmos-reading.wav';
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

