import { GoogleGenAI, Type, Modality } from "@google/genai";
import { HoroscopeReading } from "../types";

const apiKey = process.env.API_KEY || '';
const ai = new GoogleGenAI({ apiKey });

// Helper to format text for speech - centralized here for pre-generation
export const formatTextForSpeech = (data: HoroscopeReading) => {
  let text = `Greetings, stardust. Here is your unified cosmic reading. \n\n ${data.summary} \n\n`;

  const transitions = [
    "Turning to the stars,",
    "Through the lens of,",
    "The cards reveal,",
    "Spirit guides whisper,",
    "Wisdom from the void,"
  ];

  data.sections.forEach((section, index) => {
    const transition = transitions[index % transitions.length];
    text += `${transition} ${section.title}. ${section.content} \n\n`;
  });

  text += "Go forth in light.";
  return text;
};

export const generateHoroscopeText = async (
  name: string,
  birthDate: string,
  birthPlace: string,
  focus: string
): Promise<HoroscopeReading> => {
  const prompt = `
    Generate a comprehensive, gender-neutral horoscope reading for ${name}, born on ${birthDate} in ${birthPlace}.
    Focus area: ${focus}.
    Include insights from:
    1. Western Astrology (Sun, Moon, Rising if inferable, current transits)
    2. Chinese Zodiac
    3. Tarot (Simulate a 3-card spread)
    4. Native American Totem
    5. Buddhist cosmic philosophy

    Tone: Mystical, universal, empowering, non-binary.
    Format as JSON.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          summary: { type: Type.STRING },
          sections: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                title: { type: Type.STRING },
                content: { type: Type.STRING },
                icon: { type: Type.STRING }
              }
            }
          },
          luckyNumbers: { type: Type.ARRAY, items: { type: Type.NUMBER } },
          luckyColors: { type: Type.ARRAY, items: { type: Type.STRING } }
        }
      }
    }
  });

  if (!response.text) throw new Error("No text generated");
  return JSON.parse(response.text) as HoroscopeReading;
};

export const generateHoroscopeImage = async (description: string, name: string): Promise<string> => {
  // Updated prompt for abstract, androgynous, cosmic art with name integration
  const prompt = `A digital masterpiece of abstract cosmic art representing: ${description}. 
  Critically Important: Integrate the text "${name}" into the artwork. The name should be stylized and blended perfectly into the image, appearing as if formed by constellations, glowing nebula gas, or woven into sacred geometry. It should be legible but feel like a natural part of the cosmic environment.
  Style: Sacred geometry, nebula clouds, bioluminescent structures. 
  Aesthetics: Androgynous, universal, non-binary, avoiding gendered human figures. 
  Colors: Deep indigo, cyan, silver, iridescent. High quality, intricate details.`;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-image",
    contents: {
      parts: [{ text: prompt }]
    }
  });

  // Extract image
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData && part.inlineData.data) {
      return part.inlineData.data;
    }
  }
  throw new Error("No image generated");
};

export const editHoroscopeImage = async (base64Image: string, instruction: string): Promise<string> => {
  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-image",
    contents: {
      parts: [
        {
          inlineData: {
            mimeType: "image/png",
            data: base64Image
          }
        },
        { text: instruction }
      ]
    }
  });

  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData && part.inlineData.data) {
      return part.inlineData.data;
    }
  }
  throw new Error("No edited image generated");
};

export const generateTTS = async (text: string): Promise<Uint8Array> => {
  // REMOVED "ethereal" to prevent echo/reverb artifacts.
  // CHANGED to "warm, grounded" to ensure audio stability.
  const styledText = `Speak in a clear, warm, and grounded gender-neutral tone. Maintain a steady, natural conversational pace. You are a cosmic guide: ${text}`;

  const response = await ai.models.generateContent({
    model: "gemini-2.5-flash-preview-tts",
    contents: {
      parts: [{ text: styledText }]
    },
    config: {
      responseModalities: [Modality.AUDIO],
      speechConfig: {
        voiceConfig: {
          // Zephyr is often more neutral/calm/airy than Kore (fem) or Fenrir (masc)
          prebuiltVoiceConfig: { voiceName: "Zephyr" }
        }
      }
    }
  });

  const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
  if (!base64Audio) throw new Error("No audio generated");

  const binaryString = atob(base64Audio);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

import React, { useState, useEffect } from 'react';
import StarField from './components/StarField';
import InputForm from './components/InputForm';
import HoroscopeView from './components/HoroscopeView';
import LiveOracle from './components/LiveOracle';
import HistoryList from './components/HistoryList';
import { UserData, HoroscopeReading, AppState, SavedReading } from './types';
import { generateHoroscopeText, generateHoroscopeImage, generateTTS, formatTextForSpeech } from './services/geminiService';
import { saveReadingToLocal, getReadingsFromLocal, deleteReadingFromLocal } from './services/storageService';

const App: React.FC = () => {
  const [appState, setAppState] = useState<AppState>(AppState.INPUT);
  const [currentUserData, setCurrentUserData] = useState<UserData | null>(null);
  const [readingData, setReadingData] = useState<HoroscopeReading | null>(null);
  const [imageData, setImageData] = useState<string | null>(null);
  const [audioData, setAudioData] = useState<Uint8Array | null>(null);
  const [readingTimestamp, setReadingTimestamp] = useState<number | undefined>(undefined);
  const [showLive, setShowLive] = useState(false);

  // History State
  const [showHistory, setShowHistory] = useState(false);
  const [savedReadings, setSavedReadings] = useState<SavedReading[]>([]);

  // Load history on mount
  useEffect(() => {
    setSavedReadings(getReadingsFromLocal());
  }, []);

  const handleFormSubmit = async (data: UserData) => {
    setCurrentUserData(data); // Store user data for saving later
    setAppState(AppState.GENERATING);
    try {
      // Step 1: Generate Text first (needed for TTS)
      const textResult = await generateHoroscopeText(data.name, data.birthDate, data.birthPlace, data.focusArea);

      // Step 2: Prepare Text for Speech
      const speechText = formatTextForSpeech(textResult);

      // Step 3: Parallel Execution - Generate Image AND Audio simultaneously
      const [imageResult, audioResult] = await Promise.all([
        generateHoroscopeImage(
          `Abstract mashup of ${data.focusArea}, zodiac, tarot, totem. ${textResult.summary}`, 
          data.name
        ),
        generateTTS(speechText)
      ]);

      setReadingData(textResult);
      setImageData(imageResult);
      setAudioData(audioResult);
      setReadingTimestamp(Date.now());
      setAppState(AppState.READING);
    } catch (error) {
      console.error(error);
      alert("The stars are clouded. Please try again. (API Error)");
      setAppState(AppState.INPUT);
    }
  };

  const handleSaveReading = () => {
    if (!readingData || !imageData || !currentUserData) return;

    const newReading: SavedReading = {
      id: Date.now().toString(),
      timestamp: readingTimestamp || Date.now(),
      userData: currentUserData,
      readingData: readingData,
      imageData: imageData
    };

    const success = saveReadingToLocal(newReading);
    if (success) {
      setSavedReadings(getReadingsFromLocal()); // Refresh list
    } else {
      alert("Cosmic journal full. Please delete old entries.");
    }
  };

  const handleDeleteHistory = (id: string) => {
    const updated = deleteReadingFromLocal(id);
    setSavedReadings(updated);
  };

  const handleLoadHistory = (reading: SavedReading) => {
    setReadingData(reading.readingData);
    setImageData(reading.imageData);
    setAudioData(null); // No audio in history
    setCurrentUserData(reading.userData);
    setReadingTimestamp(reading.timestamp);
    setShowHistory(false);
    setAppState(AppState.READING);
  };

  const resetApp = () => {
    setAppState(AppState.INPUT);
    setReadingData(null);
    setImageData(null);
    setAudioData(null);
    setCurrentUserData(null);
    setReadingTimestamp(undefined);
  };

  return (
    <div className="min-h-screen text-slate-200 relative overflow-x-hidden">
      <StarField />

      <main className="container mx-auto px-4 py-8 relative z-10 flex flex-col items-center justify-center min-h-screen">

        {/* Logo/Header - Only show large on Input screen */}
        {appState === AppState.INPUT && (
           <header className="text-center mb-12 animate-fade-in">
             <h1 className="text-5xl md:text-7xl font-bold text-transparent bg-clip-text bg-gradient-to-b from-cyan-100 to-indigo-500 mb-4 drop-shadow-[0_0_15px_rgba(99,102,241,0.5)]">
               Omni-Cosmos
             </h1>
             <p className="text-xl text-cyan-200/80 font-light tracking-widest uppercase">
               Universal Horoscope & Guide
             </p>
           </header>
        )}

        {appState === AppState.INPUT && (
          <InputForm 
            onSubmit={handleFormSubmit} 
            isLoading={false} 
            onOpenHistory={() => setShowHistory(true)}
          />
        )}

        {appState === AppState.GENERATING && (
          <div className="text-center animate-pulse">
            <div className="w-24 h-24 mx-auto mb-8 relative">
               <div className="absolute inset-0 border-4 border-cyan-500/30 rounded-full"></div>
               <div className="absolute inset-0 border-4 border-t-cyan-400 rounded-full animate-spin"></div>
               <div className="absolute inset-4 bg-indigo-500/20 rounded-full blur-xl"></div>
            </div>
            <h2 className="text-2xl font-cinzel text-white mb-2">Harmonizing Cosmic Frequencies...</h2>
            <p className="text-cyan-200">Synthesizing voice, vision, and wisdom.</p>
          </div>
        )}

        {appState === AppState.READING && readingData && imageData && (
          <HoroscopeView 
            data={readingData} 
            imageData={imageData} 
            preloadedAudio={audioData} // May be null if loaded from history
            timestamp={readingTimestamp}
            onLiveClick={() => setShowLive(true)}
            onReset={resetApp}
            onSave={handleSaveReading}
          />
        )}
      </main>

      {showLive && (
        <LiveOracle onClose={() => setShowLive(false)} />
      )}

      {showHistory && (
        <HistoryList 
          readings={savedReadings}
          onSelect={handleLoadHistory}
          onDelete={handleDeleteHistory}
          onClose={() => setShowHistory(false)}
        />
      )}

      {/* Global CSS for Animations */}
      <style>{`
        @keyframes wave {
          0%, 100% { transform: scaleY(1); opacity: 0.5; }
